/* DTI */
function CalcDTI({isMo=false,onNav=()=>{}}){const[inc,sInc]=useState("5000");const[la,sLa]=useState("30000");const[lr,sLr]=useState("3.5");const[ly,sLy]=useState("30");const[ei,sEi]=useState("");const[existPrincipal,setExistPrincipal]=useState("");const ai=tW(inc),laW=tW(la),lrV=pN(lr)/100/12,lN=parseInt(ly)*12,eiW=tW(ei);const existPrinW=tW(existPrincipal);let na=0;if(laW>0&&lrV>0&&lN>0)na=laW*lrV*Math.pow(1+lrV,lN)/(Math.pow(1+lrV,lN)-1)*12;const tot=na+eiW*12,dti=ai>0?tot/ai*100:0;const newDTI=ai>0?(na+eiW*12+existPrinW*12)/ai*100:0;let st="양호",sc="#00875A";if(dti>60){st="한도 초과";sc="#DE350B";}else if(dti>50){st="주의";sc="#FF8B00";}return(<div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:isMo?16:32,alignItems:"start",minWidth:0}}><div>{!isMo&&<h3 style={{fontSize:isMo?16:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>DTI 계산기</h3>}<Inp label="연 소득" value={inc} onChange={sInc} suffix="만원" placeholder="예: 5000"/><Inp label="신규 대출금액" value={la} onChange={sLa} suffix="만원" placeholder="예: 30000"/><Inp label="대출 금리" value={lr} onChange={sLr} suffix="%" placeholder="예: 3.5"/><Sel label="대출 기간" value={ly} onChange={sLy} options={[5,10,15,20,25,30,35,40].map(y=>({value:String(y),label:y+"년"}))}/><div style={{fontSize:12,color:"#6b778c",marginBottom:-8,marginLeft:2,display:"flex",alignItems:"center",gap:4,flexWrap:"nowrap"}}>DTI vs DSR <TipModal title="DTI와 DSR의 차이"><p><b>DTI:</b> 신규 원리금 + 기존 이자만 포함</p><p><b>DSR:</b> 모든 대출 원금+이자 포함 (더 엄격)</p></TipModal></div><Inp label="기존 대출 월이자 합계" value={ei} onChange={sEi} suffix="만원" placeholder="없으면 0" note="DTI는 기존 대출의 이자만 포함 (원금 미포함)"/><Inp label="기존 대출 월 원금상환액 (신DTI용)" value={existPrincipal} onChange={setExistPrincipal} suffix="만원" placeholder="없으면 0" note="신DTI 계산 시 기존 대출 원금도 포함"/></div><div>{ai>0&&laW>0?<><div style={{background:"linear-gradient(135deg, #0747A6 0%, #0052CC 50%, #0065FF 100%)",borderRadius:20,padding:"28px 24px",color:"#fff",textAlign:"center",boxShadow:"0 8px 28px rgba(7,71,166,.28)"}}><div style={{fontSize:11,letterSpacing:1.5,opacity:.8,marginBottom:16}}>DTI 진단 결과</div><div style={{fontSize:52,fontWeight:800,color:sc==="#00875A"?"#57D9A3":sc==="#FF8B00"?"#FFC400":"#FF5630"}}>{fP(dti)}</div><div style={{fontSize:16,fontWeight:600,marginTop:4,color:sc==="#00875A"?"#57D9A3":sc==="#FF8B00"?"#FFC400":"#FF5630"}}>{st}</div><div style={{background:"rgba(255,255,255,.2)",borderRadius:8,height:10,margin:"12px 0 4px"}}><div style={{height:"100%",borderRadius:8,width:Math.min(dti,100)+"%",background:dti>60?"#ef4444":dti>50?"#f59e0b":"#22c55e",transition:"width .4s"}}/></div><div style={{display:"flex",justifyContent:"space-between",fontSize:10,opacity:.7,marginBottom:8}}><span>0%</span><span>60% 한도</span><span>100%</span></div><div style={{fontSize:12,opacity:.7,marginTop:8}}>규제 기준: 60%</div><div style={{borderTop:"1px solid rgba(255,255,255,.2)",marginTop:16,paddingTop:12,textAlign:"left",fontSize:13}}><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>신규 연간 원리금</span><span style={{fontWeight:600}}>{fW(na)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>기존 연간 이자</span><span style={{fontWeight:600}}>{fW(eiW*12)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>DTI (구) · 신규+기존이자</span><span style={{fontWeight:600}}>{fP(dti)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>신DTI · 신규+기존원리금</span><span style={{fontWeight:600}}>{fP(newDTI)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.7,fontSize:11}}><span>DSR과 차이</span><span>DSR이 더 엄격 (모든 원리금 포함)</span></div></div></div>{dti>0&&<div style={{marginTop:12,padding:"10px 14px",background:dti>60?"#FFEBE6":dti>40?"#FFF8E1":"#f8f9fc",border:"1px solid "+(dti>60?"#FFBDAD":dti>40?"#FFE082":"#dfe1e6"),borderRadius:8,fontSize:12,color:dti>60?"#BF2600":dti>40?"#F57F17":"#505f79",lineHeight:1.6}}>{dti>60?"DTI 한도 초과: 대출 승인 어려울 수 있습니다":dti>50?"DTI 50% 초과: 조정지역 기준 초과":dti>40?"DTI 40% 초과: 투기과열지구 기준 초과":"DTI 규제: 투기과열 40% / 조정 50% / 비규제 60%"}</div>}<div style={{marginTop:8,padding:"10px 14px",background:"#f8f9fc",border:"1px solid #dfe1e6",borderRadius:8,fontSize:12,color:"#505f79",lineHeight:1.6,display:"flex",alignItems:"center",gap:6}}><span><IconCal/></span><span>본 계산은 2026년 DTI 규제 기준 · 대출 심사 시 신용점수·직장·부양가족 등 추가 평가</span></div></>:<StepsGuide steps={[{label:"연 소득 입력",filled:ai>0},{label:"신규 대출금액 입력",filled:laW>0},{label:"대출 금리 입력",filled:pN(lr)>0}]}/>}<NextStep calcId="dti" onNav={onNav} isMo={isMo}/><RateTable title="DTI 규제 비율" headers={["지역","DTI"]} rows={[["투기지역·투기과열","40%"],["조정대상지역","50%"],["기타지역","60%"]]}/></div></div>);}

/* LTV·대출한도 */
function CalcLTV({isMo=false,onNav=()=>{}}){
  const[pv,sPv]=useState("");const[a,sA]=useState("non");const[h,sH]=useState("1");const[ex,sEx]=useState("");const[first,sFirst]=useState("no");const[seomin,sSeomin]=useState("no");
  const pvW=tW(pv),exW=tW(ex),n=parseInt(h);
  let ltv=0.70;
  if(first==="yes"){ltv=a==="non"?0.80:0.70;}
  else if(seomin==="yes"&&a==="spec"){ltv=0.60;}
  else if(seomin==="yes"&&a==="adj"){ltv=0.70;}
  else if(a==="spec"){ltv=n===1?0.40:0;}
  else if(a==="adj"){ltv=n===1?0.50:0;}
  else{ltv=n===1?0.70:0.60;}
  if(n>=3&&a!=="non")ltv=0;
  const firstTimeCap=first==="yes"?6e8:Infinity;
  const isMetro=a!=="non";
  let metroCap=Infinity;
  if(isMetro){if(pvW<=15e8)metroCap=6e8;else if(pvW<=25e8)metroCap=4e8;else metroCap=2e8;}
  const specBlocked=a==="spec"&&pvW>15e8;
  let ltvLoan;
  if(specBlocked)ltvLoan=0;
  else if(pvW>9e8&&ltv>0)ltvLoan=9e8*ltv+(pvW-9e8)*0.20;
  else ltvLoan=pvW*ltv;
  const over9Applied=pvW>9e8&&!specBlocked&&ltv>0;
  const capped=Math.min(ltvLoan,metroCap,firstTimeCap);
  const ml=Math.max(0,capped-exW);
  const equity=Math.max(0,pvW-Math.max(0,ml));
  const isCappedByRegulation=ltv>0&&ltvLoan>metroCap;
  const alertMsg=(ltv===0||specBlocked)?"해당 조건에서 주택담보대출이 제한됩니다":first==="yes"?"생애최초: LTV "+fP(ltv*100)+" 적용 (한도 6억)":seomin==="yes"?"서민실수요자 우대: LTV "+fP(ltv*100)+" 적용":null;
  const alertType=(ltv===0||specBlocked)?"danger":"success";
  const ltvBarColor=ltv>=0.7?"#22c55e":ltv>=0.5?"#3b82f6":ltv>0?"#f59e0b":"#94a3b8";
  const rpItems=[{l:"주택 가격",v:fW(pvW)},{l:"적용 LTV",v:ltv===0?"대출 불가":fP(ltv*100)}];
  if(over9Applied)rpItems.push({l:"  9억 초과분 LTV",v:"20%",note:"초과분 "+fW(pvW-9e8)+" 적용"});
  if(specBlocked)rpItems.push({l:"  15억 초과",v:"주담대 불가",note:"투기과열지구 제한"});
  rpItems.push({l:"LTV 기준 최대 대출",v:fW(Math.max(0,capped))});
  if(isMetro&&metroCap!==Infinity)rpItems.push({l:"수도권 주담대 한도",v:fW(metroCap)});
  if(exW>0)rpItems.push({l:"기존 대출 차감",v:"-"+fW(exW)});
  rpItems.push({l:"실제 대출 가능액",v:fW(Math.max(0,ml))});
  rpItems.push({l:"필요 자기자본",v:fW(equity),note:"매수가 - 최대대출"});
  rpItems.push({l:"자기자본 비율",v:fP(pvW>0?equity/pvW*100:0)});
  return(<div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:isMo?16:32,alignItems:"start",minWidth:0}}><div>{!isMo&&<h3 style={{fontSize:isMo?16:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>LTV 계산기</h3>}<Inp label="주택 가격 (시세)" value={pv} onChange={sPv} suffix="만원" placeholder="예: 90000"/><Tog label="규제지역" value={a} onChange={sA} options={[{value:"non",label:"비규제"},{value:"adj",label:"조정대상"},{value:"spec",label:"투기과열"}]}/><Sel label="주택 수" value={h} onChange={sH} options={[{value:"1",label:"1주택 (무주택 포함)"},{value:"2",label:"2주택"},{value:"3",label:"3주택 이상"}]}/><Radio label="우대 조건 (상호배타)" value={first==="yes"?"first":seomin==="yes"?"seomin":"none"} onChange={v=>{sFirst(v==="first"?"yes":"no");sSeomin(v==="seomin"?"yes":"no");}} options={[{value:"none",label:"해당없음"},{value:"first",label:"생애최초 (비규제80%/규제70%, 한도6억)"},{value:"seomin",label:"서민실수요자 (투기60%/조정70%)"}]} cols={3}/><Inp label="기존 담보대출 잔액" value={ex} onChange={sEx} suffix="만원" placeholder="없으면 0"/>{isCappedByRegulation&&<div style={{padding:"12px 16px",background:"#FFF8E1",border:"1px solid #FFE082",borderRadius:10,fontSize:13,color:"#F57F17",marginTop:12,lineHeight:1.6,display:"flex",alignItems:"center",gap:6}}><IconWarn c="#F57F17"/> LTV 기준 {fW(ltvLoan)} 가능하나, 수도권·규제지역 주담대 한도({metroCap===6e8?"6억":metroCap===4e8?"4억":"2억"})로 제한됩니다. (2025.6.28~ 시행)</div>}</div><div>{pvW<=0&&<RequiredGuide items={[{label:"주택 가격 (시세)",filled:pvW>0}]}/>}<><div style={{margin:"0 0 16px"}}><div style={{display:"flex",justifyContent:"space-between",fontSize:11,marginBottom:4,color:"#475569"}}><span style={{fontWeight:600}}>LTV {fP(ltv*100)}</span><span style={{color:"#64748b"}}>{ltv===0?"대출 제한":"한도 내"}</span></div><div style={{background:"#e2e8f0",borderRadius:6,height:10,overflow:"hidden"}}><div style={{height:"100%",borderRadius:6,width:Math.min(ltv*100,100)+"%",background:ltvBarColor,transition:"width .4s"}}/></div><div style={{display:"flex",justifyContent:"space-between",fontSize:10,color:"#94a3b8",marginTop:4}}><span>0%</span><span>50%</span><span>100%</span></div></div><RP title={ltv===0?"대출 제한":"LTV·대출한도 분석"}
      deadline="LTV 초과 시 자기자본으로 충당 / 잔금일 전 대출 승인 필요 (최소 2~3주 전 신청)"
      alertMsg={alertMsg} alertType={alertType}
      total={ml} sub={ltv===0?(n>=3&&a!=="non"?"규제지역 3주택 이상 주담대 금지":"규제지역 다주택자 주택담보대출 제한"):"LTV "+fP(ltv*100)+(isCappedByRegulation?" + 주담대 한도":"")+" 적용"} items={rpItems} consultFunnel={ltv===0||specBlocked?{label:<><IconWarn c="#fff"/> 추가 대출 방법 상담</>,color:"#FF8B00",subtitle:"LTV 한도 초과·주담대 제한 — 보금자리론·신혼부부 특례 등 대안 상담"}:isCappedByRegulation?{label:<><IconMoney c="#fff"/> 추가 대출 방법 상담</>,color:"#FF8B00",subtitle:"수도권 주담대 한도 적용 — LTV 초과분 충당 전략 상담"}:null}/></><NextStep calcId="ltv" onNav={onNav} isMo={isMo}/><RateTable title="LTV 규제 비율 (2026)" headers={["지역","무주택","서민실수요","생애최초","1주택자추가"]} rows={[["투기과열","40%","60%","70%(한도6억)","불가"],["조정대상","50%","70%","70%(한도6억)","불가"],["비규제","70%","-","80%(한도6억)","60%"]]}/></div></div>);}

/* 2026.04.14 고도화: RTI(Rent To Interest) 계산기 신규 추가 - 임대사업자 주담대 심사비율 */
function CalcRti({isMo=false,onNav=()=>{}}){
  const[propType,setPT]=useState("res");
  const[rentAnnual,setRA]=useState("2400");
  const[loanAmt,setLA]=useState("50000");
  const[interestRate,setIR]=useState("5.0");
  const rentW=tW(rentAnnual),loanW=tW(loanAmt);
  const irV=pN(interestRate)/100;
  const annualInterest=Math.round(loanW*irV);
  const rti=annualInterest>0?rentW/annualInterest:0;
  const minRatio=propType==="res"?1.25:1.5;
  const pass=rti>=minRatio;
  const gapLoan=irV>0?Math.round(rentW/minRatio/irV):0;
  const sc=pass?"#00875A":"#DE350B";
  const st=pass?"심사 통과":"기준 미달";
  return(<div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:isMo?16:32,alignItems:"start",minWidth:0}}><div>
    {!isMo&&<h3 style={{fontSize:isMo?16:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>RTI 계산기</h3>}
    <div style={{fontSize:12,color:"#6b778c",marginBottom:-8,marginLeft:2,display:"flex",alignItems:"center",gap:4,flexWrap:"nowrap"}}>건물 유형 <TipModal title="RTI (Rent To Interest)"><p>임대사업자 주택담보대출 심사 비율.</p><p><b>RTI = 연간 임대소득 / 연간 이자비용</b></p><ul style={{paddingLeft:20}}><li>주거용 (주택): 1.25배 이상</li><li>비주거용 (상가·오피스텔·공장): 1.5배 이상</li></ul><p>2018.3.26 여신심사 가이드라인 도입. 임대사업자 등록 대출 시 필수.</p></TipModal></div>
    <Tog label="건물 유형" value={propType} onChange={setPT} options={[{value:"res",label:"주거용 (1.25배)"},{value:"biz",label:"비주거용 (1.5배)"}]}/>
    <Inp label="연간 임대소득" value={rentAnnual} onChange={setRA} suffix="만원" placeholder="예: 2400 (월 200만)" note="월 임대료 × 12 + 보증금 운용수익"/>
    <Inp label="대출금액" value={loanAmt} onChange={setLA} suffix="만원" placeholder="예: 50000"/>
    <Inp label="연 금리" value={interestRate} onChange={setIR} suffix="%" placeholder="예: 5.0"/>
  </div><div>
    {rentW>0&&loanW>0?<><div style={{background:"linear-gradient(135deg, #0747A6 0%, #0052CC 50%, #0065FF 100%)",borderRadius:20,padding:"28px 24px",color:"#fff",textAlign:"center",boxShadow:"0 8px 28px rgba(7,71,166,.28)"}}>
      <div style={{fontSize:11,letterSpacing:1.5,opacity:.8,marginBottom:16}}>RTI 분석 결과</div>
      <div style={{fontSize:52,fontWeight:800,color:pass?"#57D9A3":"#FF5630",fontVariantNumeric:"tabular-nums"}}>{rti.toFixed(2)}배</div>
      <div style={{fontSize:16,fontWeight:600,marginTop:4,color:pass?"#57D9A3":"#FF5630"}}>{st}</div>
      <div style={{background:"rgba(255,255,255,.2)",borderRadius:8,height:12,margin:"12px 0 4px"}}>
        <div style={{height:"100%",borderRadius:8,width:Math.min(rti/3*100,100)+"%",background:pass?"#22c55e":"#ef4444",transition:"width .4s"}}/>
      </div>
      <div style={{display:"flex",justifyContent:"space-between",fontSize:10,opacity:.7,marginBottom:8}}><span>0배</span><span>{minRatio}배 기준</span><span>3배</span></div>
      <div style={{fontSize:12,opacity:.7,marginTop:8}}>{propType==="res"?"주거용 1.25배":"비주거용 1.5배"} 기준</div>
      <div style={{borderTop:"1px solid rgba(255,255,255,.2)",marginTop:16,paddingTop:12,textAlign:"left",fontSize:13}}>
        <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>연간 임대소득</span><span style={{fontWeight:600}}>{fW(rentW)}</span></div>
        <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>연간 이자비용</span><span style={{fontWeight:600}}>{fW(annualInterest)}</span></div>
        <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>최대 대출 (기준 충족)</span><span style={{fontWeight:600}}>{fW(gapLoan)}</span></div>
      </div>
    </div>
    <div style={{marginTop:12,padding:"10px 14px",background:pass?"#E3FCEF":"#FFEBE6",border:"1px solid "+(pass?"#57D9A3":"#FFBDAD"),borderRadius:8,fontSize:12,color:pass?"#006644":"#BF2600",lineHeight:1.6}}>{pass?"✓ 기준 충족 — 임대사업자 대출 심사 RTI 요건 통과":"기준 미달 — 대출금액 축소 또는 임대료 조정 필요. 기준 충족 최대대출: "+fW(gapLoan)}</div>
    <div style={{marginTop:8,padding:"10px 14px",background:"#f8f9fc",border:"1px solid #dfe1e6",borderRadius:8,fontSize:12,color:"#505f79",lineHeight:1.6,display:"flex",alignItems:"center",gap:6}}><span><IconCal/></span><span>2018.3.26 여신심사 가이드라인 시행. 임대사업자 주담대 심사 필수 항목</span></div></>:<StepsGuide steps={[{label:"연간 임대소득 입력",filled:rentW>0},{label:"대출금액 입력",filled:loanW>0},{label:"금리 입력",filled:pN(interestRate)>0}]}/>}
    <NextStep calcId="rti" onNav={onNav} isMo={isMo}/>
    <RateTable title="RTI 심사 기준" headers={["건물 유형","최소 RTI","근거"]} rows={[["주거용 (주택·아파트)","1.25배","여신심사 가이드라인"],["비주거용 (상가·오피스텔·공장)","1.5배","여신심사 가이드라인"]]}/>
  </div></div>);
}

/* 2026.04.14 청약가점 계산기 (주택공급에 관한 규칙 §28) */
function CalcSubscription({isMo=false,onNav=()=>{}}){
  const[noHouseY,setNoHouseY]=useState("5");
  const[family,setFamily]=useState("2");
  const[bankY,setBankY]=useState("5");
  const ny=parseInt(noHouseY);const fm=parseInt(family);const by=parseInt(bankY);
  // 무주택기간 (최대 32점): 1년 미만 2점, 이후 2점씩 증가, 15년 이상 32점
  const noHouseScore=Math.min(32,2+ny*2);
  // 부양가족수 (최대 35점): 0명 5점, 1명 10점 ... 6명 이상 35점
  const familyScore=Math.min(35,5+fm*5);
  // 청약통장 가입기간 (최대 17점): 6개월 미만 1점, 6~12개월 2점, 1~2년 3점, 이후 +1점씩, 15년 이상 17점
  const bankScore=by===0?1:Math.min(17,by+2);
  const total=noHouseScore+familyScore+bankScore;
  let eligibility="",tier="";
  if(total>=70){eligibility="강남·용산·한강벨트 최상급 단지 당첨 가능권";tier="strong";}
  else if(total>=60){eligibility="서울 도심·핵심 입지 인기 단지 당첨 가능권";tier="strong";}
  else if(total>=50){eligibility="서울 비핵심·수도권 신도시 중위 단지 당첨 가능";tier="medium";}
  else if(total>=40){eligibility="경기 외곽·광역시 단지 당첨 가능";tier="medium";}
  else{eligibility="점수가 낮습니다. 무주택기간·부양가족·통장가입기간 확보로 점수 확대 필요";tier="weak";}
  const barColor=tier==="strong"?"#22c55e":tier==="medium"?"#f59e0b":"#ef4444";
  const alertBg=tier==="strong"?"#E3FCEF":tier==="medium"?"#FFF8E1":"#FFEBE6";
  const alertBd=tier==="strong"?"#57D9A3":tier==="medium"?"#FFE082":"#FFBDAD";
  const alertTc=tier==="strong"?"#006644":tier==="medium"?"#F57F17":"#BF2600";
  const ySel=Array.from({length:16},(_,i)=>({value:String(i),label:i===0?"1년 미만":i===15?"15년 이상":`${i}~${i+1}년`}));
  const bSel=Array.from({length:16},(_,i)=>({value:String(i),label:i===0?"6개월 미만":i===1?"6개월~1년":i===15?"15년 이상":`${i}~${i+1}년`}));
  return(<div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:isMo?16:32,alignItems:"start",minWidth:0}}><div>
    {!isMo&&<h3 style={{fontSize:isMo?16:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>청약가점 계산기</h3>}
    <div style={{fontSize:12,color:"#6b778c",marginBottom:-8,marginLeft:2,display:"flex",alignItems:"center",gap:4,flexWrap:"nowrap"}}>무주택기간 <TipModal title="무주택기간 산정"><p>만 30세부터 기산. 기혼자는 혼인신고일이 빠르면 혼인신고일부터. 주택 처분 후 재취득 시 초기화.</p><p>최대 32점 (1년 미만 2점, 1~2년 4점, ..., 15년 이상 32점).</p></TipModal></div>
    <Sel label="무주택기간" value={noHouseY} onChange={setNoHouseY} options={ySel}/>
    <div style={{fontSize:12,color:"#6b778c",marginBottom:-8,marginLeft:2,display:"flex",alignItems:"center",gap:4,flexWrap:"nowrap"}}>부양가족 수 <TipModal title="부양가족 수"><p>본인 제외, 배우자·직계존속·직계비속 중 세대를 같이하는 사람. 최대 35점 (0명 5점, 1명 10점, ..., 6명 이상 35점).</p></TipModal></div>
    <Sel label="부양가족 수 (본인 제외)" value={family} onChange={setFamily} options={[{value:"0",label:"0명"},{value:"1",label:"1명"},{value:"2",label:"2명"},{value:"3",label:"3명"},{value:"4",label:"4명"},{value:"5",label:"5명"},{value:"6",label:"6명 이상"}]}/>
    <div style={{fontSize:12,color:"#6b778c",marginBottom:-8,marginLeft:2,display:"flex",alignItems:"center",gap:4,flexWrap:"nowrap"}}>청약통장 <TipModal title="청약통장 가입기간"><p>청약저축·청약예금·청약부금·주택청약종합저축. 최대 17점 (6개월 미만 1점, 6~12개월 2점, 1~2년 3점, 이후 매년 +1점).</p></TipModal></div>
    <Sel label="청약통장 가입기간" value={bankY} onChange={setBankY} options={bSel}/>
  </div><div>
    <div style={{background:"linear-gradient(135deg, #0747A6 0%, #0052CC 50%, #0065FF 100%)",borderRadius:20,padding:"28px 24px",color:"#fff",textAlign:"center",boxShadow:"0 8px 28px rgba(7,71,166,.28)"}}>
      <div style={{fontSize:11,letterSpacing:1.5,opacity:.8,marginBottom:16}}>청약가점 합계 (84점 만점)</div>
      <div style={{fontSize:60,fontWeight:800,color:barColor,fontVariantNumeric:"tabular-nums",lineHeight:1}}>{total}<span style={{fontSize:24,marginLeft:6,fontWeight:700,color:"#fff",opacity:.7}}>점</span></div>
      <div style={{background:"rgba(255,255,255,.2)",borderRadius:8,height:12,margin:"16px 0 4px"}}>
        <div style={{height:"100%",borderRadius:8,width:Math.min(total/84*100,100)+"%",background:barColor,transition:"width .4s"}}/>
      </div>
      <div style={{display:"flex",justifyContent:"space-between",fontSize:10,opacity:.7,marginBottom:8}}><span>0점</span><span>40점</span><span>60점</span><span>84점</span></div>
      <div style={{borderTop:"1px solid rgba(255,255,255,.2)",marginTop:16,paddingTop:12,textAlign:"left",fontSize:13}}>
        <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.9}}><span>무주택기간</span><span style={{fontWeight:700}}>{noHouseScore} / 32점</span></div>
        <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.9}}><span>부양가족수</span><span style={{fontWeight:700}}>{familyScore} / 35점</span></div>
        <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.9}}><span>청약통장</span><span style={{fontWeight:700}}>{bankScore} / 17점</span></div>
      </div>
    </div>
    <div style={{marginTop:12,padding:"12px 16px",background:alertBg,border:"1px solid "+alertBd,borderRadius:10,fontSize:13,color:alertTc,lineHeight:1.6}}>
      <div style={{fontWeight:700,marginBottom:4,display:"flex",alignItems:"center",gap:6}}><IconPin/> 내 점수로 당첨 가능한 단지</div>
      {eligibility}
    </div>
    <div style={{marginTop:8,padding:"10px 14px",background:"#f8f9fc",border:"1px solid #dfe1e6",borderRadius:8,fontSize:12,color:"#505f79",lineHeight:1.6,display:"flex",alignItems:"center",gap:6}}><span><IconCal/></span><span>본 점수는 가점제 기준 · 추첨제·특별공급은 별도 기준 · 청약홈(applyhome.co.kr) 공식 확인</span></div>
    <NextStep calcId="subscription" onNav={onNav} isMo={isMo}/>
    <RateTable title="청약가점 배점표" headers={["항목","만점","비고"]} rows={[["무주택기간","32점","1년당 2점, 15년 이상 만점"],["부양가족수","35점","1명당 5점, 6명 이상 만점"],["청약통장 가입기간","17점","1년 이상부터 매년 +1점, 15년 이상 만점"],["합계","84점","가점제 최고점"]]}/>
  </div></div>);
}

/* 2026.04.14 매도 실수령액 계산기 */
function CalcNetSale({isMo=false,onNav=()=>{}}){
  const[sellP,setSellP]=useState("100000");
  const[buyP,setBuyP]=useState("70000");
  const[holdY,setHoldY]=useState("5");
  const[autoTax,setAutoTax]=useState("yes");
  const[manualTax,setManualTax]=useState("");
  const[commRate,setCommRate]=useState("0.5");
  const[otherCost,setOtherCost]=useState("");
  const sellW=tW(sellP),buyW=tW(buyP);
  const hy=parseInt(holdY)||0;
  const gain=Math.max(0,sellW-buyW);
  // 자동 추정 양도세 (간이): 1년 미만 70%, 1~2년 60%, 2년 이상 평균 22% 누진 근사값
  let autoTaxVal=0;
  if(autoTax==="yes"&&gain>0){
    if(hy<1)autoTaxVal=Math.round(gain*0.70);
    else if(hy<2)autoTaxVal=Math.round(gain*0.60);
    else{
      const taxBase=Math.max(0,gain-2.5e6);
      const IB=[[14e6,.06,0],[50e6,.15,126e4],[88e6,.24,576e4],[1.5e8,.35,1544e4],[3e8,.38,1994e4],[5e8,.40,2594e4],[10e8,.42,3594e4],[Infinity,.45,6594e4]];
      for(const[lim,rate,ded]of IB){if(taxBase<=lim){autoTaxVal=Math.round(taxBase*rate-ded);break;}}
      autoTaxVal=Math.round(autoTaxVal*1.10); // 지방소득세 10% 포함
    }
  }
  const taxVal=autoTax==="yes"?autoTaxVal:tW(manualTax);
  const commW=Math.round(sellW*(pN(commRate)/100));
  const otherW=tW(otherCost);
  const net=sellW-taxVal-commW-otherW;
  const hySel=Array.from({length:31},(_,i)=>({value:String(i),label:i===0?"1년 미만":`${i}년`}));
  return(<div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:isMo?16:32,alignItems:"start",minWidth:0}}><div>
    {!isMo&&<h3 style={{fontSize:isMo?16:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>매도 실수령액 계산기</h3>}
    <Inp label="매도가격" value={sellP} onChange={setSellP} suffix="만원" placeholder="예: 100000"/>
    <Inp label="취득가격" value={buyP} onChange={setBuyP} suffix="만원" placeholder="예: 70000"/>
    <Sel label="보유기간" value={holdY} onChange={setHoldY} options={hySel}/>
    <Tog label="양도세 계산 방식" value={autoTax} onChange={setAutoTax} options={[{value:"yes",label:"자동 추정"},{value:"no",label:"직접 입력"}]}/>
    {autoTax==="no"&&<Inp label="양도소득세 (직접 입력)" value={manualTax} onChange={setManualTax} suffix="만원" placeholder="정확한 계산은 양도세 계산기 참조"/>}
    <Inp label="중개수수료율" value={commRate} onChange={setCommRate} suffix="%" note="법정 상한 0.4~0.9% (거래금액별 차등)"/>
    <Inp label="기타 비용" value={otherCost} onChange={setOtherCost} suffix="만원" placeholder="법무사·명도·이사 등" note="없으면 0"/>
  </div><div>
    <RP title="매도 실수령액" total={Math.max(0,net)} sub={"매도가 "+fW(sellW)+" 기준"}
      alertMsg={autoTax==="yes"?"양도세 자동 추정 — 정확한 계산은 양도소득세 계산기에서 장특공·공제·중과 반영":net<0?"실수령액이 음수 — 비용이 매도가를 초과":gain===0?"양도차익 없음 — 취득가≥매도가":null}
      alertType={net<0?"danger":autoTax==="yes"?"warning":"info"}
      deadline="잔금 수령일 = 양도일 · 신고기한 2개월 · 예정신고 후 확정신고 필요"
      deadlineLink="https://hometax.go.kr" deadlineLinkLabel="홈택스 신고 →"
      items={[
        {l:"매도가액",v:fW(sellW)},
        {l:"(-) 취득가액",v:"-"+fW(buyW),note:"참고"},
        {l:"= 양도차익",v:fW(gain),note:gain===0?"손실":""},
        {l:"(-) 양도소득세",v:"-"+fW(taxVal),note:autoTax==="yes"?(hy<1?"1년↓ 70%":hy<2?"2년↓ 60%":"2년↑ 누진+지방세"):"직접 입력"},
        {l:"(-) 중개수수료",v:"-"+fW(commW),note:commRate+"%"},
        {l:"(-) 기타비용",v:"-"+fW(otherW)},
        {l:"= 실수령액",v:fW(net)}
      ]}/>
    <NextStep calcId="netsale" onNav={onNav} isMo={isMo}/>
  </div></div>);
}

/* 2026.04.14 부동산 용어사전 진입: 정적 HTML로 리다이렉트 */
