function CalcCarTax({isMo=false,onNav=()=>{}}){const[carType,sCT]=useState("normal");const[cc,sCC]=useState("2000");const[year,sYear]=useState("0");const[isElec,sElec]=useState("no");
  const ccVal=parseInt(cc)||0,yearVal=parseInt(year)||0;let baseTax=0;
  if(isElec==="yes"){baseTax=100000;}else if(carType==="normal"){baseTax=ccVal<=1000?ccVal*80:ccVal<=1600?ccVal*140:ccVal*200;}else{baseTax=ccVal<=1000?ccVal*18:ccVal<=1600?ccVal*18:ccVal*19;}
  let discount=0;if(yearVal>=3)discount=Math.min((yearVal-2)*.05,.50);
  const discountedTax=Math.round(baseTax*(1-discount)),localEdu=Math.round(discountedTax*.3),totalYear=discountedTax+localEdu,halfYear=Math.round(totalYear/2);
  return(<div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:isMo?16:32,alignItems:"start",minWidth:0}}><div>{!isMo&&<h3 style={{fontSize:isMo?16:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>자동차세</h3>}
    <Tog label="전기·수소차 여부" value={isElec} onChange={sElec} options={[{value:"no",label:"내연기관"},{value:"yes",label:"전기차·수소차"}]}/>
    {isElec==="no"&&<><Tog label="차량 용도" value={carType} onChange={sCT} options={[{value:"normal",label:"비영업용 (자가용)"},{value:"biz",label:"영업용"}]}/><Inp label="배기량" value={cc} onChange={sCC} suffix="cc" placeholder="예: 2000" note="차량등록증 확인"/></>}
    <Sel label="차량 연식" value={year} onChange={sYear} options={[{value:"0",label:"신차 (1년 미만)"},{value:"1",label:"1년"},{value:"2",label:"2년"},{value:"3",label:"3년 (5% 할인)"},{value:"5",label:"5년 (15%)"},{value:"7",label:"7년 (25%)"},{value:"10",label:"10년 (40%)"},{value:"12",label:"12년+ (50% 최대)"}]}/>
    <div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.6,marginTop:8}}>※ 6월·12월 연 2회 납부 / 1월 연납 시 약 5% 할인</div>
  </div><RP title="자동차세 (연간)"
      deadline="납부: 6월·12월 연 2회 (1월 연납 시 5% 할인)"
      deadlineLink="https://wetax.go.kr" deadlineLinkLabel="위택스 →"
      alertMsg={isElec==="yes"?"전기차 정액 100,000원 (배기량 무관)":discount>=0.5?"최대 할인 50% 적용 (12년+)":yearVal<3?"3년 미만: 차령 할인 없음":null}
      alertType="info"
      total={totalYear} sub={discount>0?"차령 할인 "+Math.round(discount*100)+"%":"할인 없음 (3년 미만)"} items={[{l:"기본 자동차세",v:fW(baseTax),note:isElec==="yes"?"전기·수소차 정액":ccVal+"cc 기준"},{l:"차령 할인",v:discount>0?"-"+fW(baseTax-discountedTax):"해당없음",note:discount>0?Math.round(discount*100)+"%":""},{l:"할인 후 자동차세",v:fW(discountedTax)},{l:"지방교육세 (30%)",v:fW(localEdu)},{l:"연간 합계",v:fW(totalYear)},{l:"6월 납부",v:fW(halfYear)},{l:"12월 납부",v:fW(totalYear-halfYear)},{l:"1월 연납 시 (5% 할인)",v:fW(Math.round(totalYear*.95)),note:"✓ 추천"}]}/></div>);}

