      {(isWorker?[["국민연금 (4.75%)",npn],["건강보험 (3.595%)",hi],["장기요양 (12.95%)",ltc],["고용보험 (0.9%)",ei]]:[["국민연금 (9.5%)",selfNpn],["건강보험 (3.595%)",selfHi],["장기요양 (12.95%)",Math.round(selfHi*.1295)]]).map(([l,v],i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid "+P.lt,fontSize:13}}><span style={{color:P.mt}}>{l}</span><span style={{fontWeight:600,color:"#DE350B"}}>-{fW(v)}</span></div>))}
